// 1. On récupère les posts
const items = $input.all().map(item => item.json);

// RÉGLAGE : On passe à 12 mois pour voir plus loin dans le passé
const limiteDate = new Date();
limiteDate.setMonth(limiteDate.getMonth() - 12); 

let postsTexte = "";
let compteur = 1;

for (const item of items) {
  if (item.object === "PostList" && item.items) {
    for (const post of item.items) {
      // Optionnel : si tu veux aussi les reposts, supprime la ligne suivante
      if (post.is_repost === true) continue;

      const datePost = new Date(post.parsed_datetime);

      // Si le post est plus récent que 12 mois, on le prend
      if (datePost >= limiteDate) {
        postsTexte += `POST ${compteur} :\n${post.text}\n\n`;
        compteur++;
      }
    }
  }
}

// 2. RÉCUPÉRATION DU PROVIDER_ID DEPUIS LE NOEUD 'If'
const providerId = $('If').first().json.provider_id;

// 3. Récupération des autres infos depuis 'RECUP RELATION1'
const prospectData = $('RECUP RELATION1').first().json;

const prenom = prospectData.first_name || "Candidat";
const nom = prospectData.last_name || "";
const poste = prospectData.headline || "Poste non renseigné";
const emailPro = prospectData.email || "";

// 4. On renvoie le package complet
return [{
  json: {
    prenom: prenom,
    nom: nom,
    poste: poste,
    posts_texte: postsTexte.trim() || "Pas de posts originaux sur les 12 derniers mois.",
    provider_id: providerId,
    job_title: poste,
    email_pro: emailPro
  }
}];

